#!/usr/bin/env node
/**
 * Verify that tools.json annotations match BUILTIN_TOOLS in builtin.mjs.
 *
 * CANONICAL SOURCE: src/agent/orchestrator/tools/builtin.mjs (BUILTIN_TOOLS)
 * DERIVED OUTPUT:   tools.json (generated by scripts/build-tools-manifest.mjs)
 *
 * This script compares `annotations` for every tool that appears in both
 * sources and exits non-zero on any mismatch. Run after editing BUILTIN_TOOLS
 * or after regenerating tools.json to confirm they are in sync.
 *
 * Usage:  node scripts/check-tools-sync.mjs
 */

import { readFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath, pathToFileURL } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const PLUGIN_ROOT = join(__dirname, '..');

// Load tools.json (derived)
const toolsJson = JSON.parse(readFileSync(join(PLUGIN_ROOT, 'tools.json'), 'utf8'));
const jsonByName = Object.fromEntries(toolsJson.map(t => [t.name, t]));

// Load BUILTIN_TOOLS (canonical)
globalThis.__tribFastEntry = true;
process.env.CLAUDE_PLUGIN_ROOT ??= PLUGIN_ROOT;
// Provide a dummy DATA dir so module init doesn't fail
import { mkdtempSync, rmSync } from 'fs';
import { tmpdir } from 'os';
let _tmp = null;
if (!process.env.CLAUDE_PLUGIN_DATA) {
  _tmp = mkdtempSync(join(tmpdir(), 'mixdog-sync-check-'));
  process.env.CLAUDE_PLUGIN_DATA = _tmp;
}

const url = pathToFileURL(join(PLUGIN_ROOT, 'src/agent/orchestrator/tools/builtin.mjs')).href;
const { BUILTIN_TOOLS } = await import(url);

let failures = 0;
for (const builtinTool of BUILTIN_TOOLS) {
  if (builtinTool?.public === false) continue;
  const { name, annotations: builtinAnnotations } = builtinTool;
  if (!builtinAnnotations) continue;
  const jsonTool = jsonByName[name];
  if (!jsonTool) {
    console.error(`[check-tools-sync] MISSING in tools.json: ${name}`);
    failures++;
    continue;
  }
  const jsonAnnotations = jsonTool.annotations || {};
  for (const [key, builtinVal] of Object.entries(builtinAnnotations)) {
    const jsonVal = jsonAnnotations[key];
    if (jsonVal !== builtinVal) {
      console.error(
        `[check-tools-sync] MISMATCH tools.json vs builtin.mjs: ` +
        `${name}.annotations.${key} = ${JSON.stringify(jsonVal)} (json) ` +
        `vs ${JSON.stringify(builtinVal)} (builtin)`
      );
      failures++;
    }
  }
  // Check for annotations present in json but missing from builtin
  for (const key of Object.keys(jsonAnnotations)) {
    if (!(key in builtinAnnotations)) {
      console.error(
        `[check-tools-sync] EXTRA in tools.json not in builtin.mjs: ` +
        `${name}.annotations.${key} = ${JSON.stringify(jsonAnnotations[key])}`
      );
      failures++;
    }
  }
}

if (_tmp) {
  try { rmSync(_tmp, { recursive: true, force: true }); } catch { /* ignore */ }
}

if (failures > 0) {
  console.error(`[check-tools-sync] FAIL: ${failures} mismatch(es). Re-run scripts/build-tools-manifest.mjs to regenerate tools.json.`);
  process.exit(1);
} else {
  console.error(`[check-tools-sync] OK: all ${BUILTIN_TOOLS.filter(t => t?.public !== false && t?.annotations).length} annotated tools in sync.`);
  process.exit(0);
}
